compliant:
class BaseClass
{
    internal virtual void MyMethod(string str) => Console.WriteLine("BaseClass");
}

class DerivedClass : BaseClass
{
    internal override void MyMethod(string str) => Console.WriteLine("DerivedClass"); // Compliant - proper override
}

class Animal
{
    public virtual void Move(int speed) { }
}

class Dog : Animal
{
    public override void Move(int speed) { } // Compliant - same parameter type
    public void Move(string direction) { } // Compliant - different parameter type (overload)
}
